mapper.update:
UPDATE attachment
SET date_modified = now(), user_id_modified = #{userIdModified}, flag_deleted = '1'
WHERE attachment_idx = #{attachmentIdx}

mapper.select:
select IFNULL(max(b.attachment_order) + 1, 1)
from attachment b
where b.board_idx = #{boardIdx} and b.board_article_idx = #{boardArticleIdx}
